import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Sanitize and escape user input before including it in the HTML page
        String sanitizedUserInput = Encode.forHtml(userInput);

        // Output the HTML page with the sanitized user input
        String output = "<html><body>Welcome, " + sanitizedUserInput + "</body></html>";

        // Output the HTML page with the sanitized user input
        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
